                    "temp_id": a.temp_id,
                    "model_name": a.model_name,
                    "task_description": a.task_description,
                    "references": a.references,
                }
                for a in subsystem_artifacts
            ],
        })

    return specs_by_model, subsystem_map_entries, new_drafted_elements

async def _run_tactical_planning(
    self,
    user_goal: str,
    subsystems: List[Dict[str, Any]],
    existing_artifacts: Optional[List[Dict[str, Any]]] = None,
) -> tuple[Dict[str, List[ArtifactSpec]], Dict[str, str]]:
    """
    Phase 2: Draft artifacts per subsystem using wave-based parallel execution.

    Subsystems are grouped into dependency waves; all subsystems within a wave
    are drafted concurrently via asyncio.gather(). Each wave's outputs are
    accumulated into `drafted_elements` before the next wave begins, ensuring
    child subsystems receive parent context for injection.

    Returns:
        (all_specs, subsystem_map) where subsystem_map is temp_id → subsystem_id
    """
    all_specs: Dict[str, List[ArtifactSpec]] = {}
    subsystem_map: Dict[str, str] = {}
    drafted_elements: List[Dict[str, Any]] = []

    existing_context = ""
    if existing_artifacts:
        existing_context = (
            f"\nEXISTING INFRASTRUCTURE (Base Layer for linkage):\n"
            f"{json.dumps(existing_artifacts, indent=2)}"
        )

    waves = self._compute_drafting_waves(subsystems)
    logger.info(
        f"[tactical_planner] §4.6 Parallel drafting: {len(subsystems)} subsystems "
        f"in {len(waves)} wave(s): {[[s['id'] for s in w] for w in waves]}"
    )

    for wave_idx, wave in enumerate(waves):
        # Snapshot drafted_elements for all subsystems in this wave — they see
        # the same context (outputs from completed waves, not each other's).
        context_snapshot = list(drafted_elements)

        wave_results = await asyncio.gather(*[
            self._draft_one_subsystem(sub, user_goal, context_snapshot, existing_context)
            for sub in wave
        ])

        for specs_by_model, sub_map_entries, new_elements in wave_results:
            for model_name, specs in specs_by_model.items():
                if model_name not in all_specs:
                    all_specs[model_name] = []
                all_specs[model_name].extend(specs)
            subsystem_map.update(sub_map_entries)
            drafted_elements.extend(new_elements)

        logger.info(
            f"[tactical_planner] Wave {wave_idx} complete: "
            f"{len(subsystem_map)} total artifact mappings so far"
        )

    return all_specs, subsystem_map

def _topo_sort_subsystems(self, subsystems: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    """Simple topological sort for subsystems."""
    sub_map = {s["id"]: s for s in subsystems}
    adj = {s["id"]: s.get("depends_on", []) for s in subsystems}
    visited = set()
    stack = []

    def visit(node_id):
        if node_id in visited: return
        for dep in adj.get(node_id, []):
            if dep in sub_map: visit(dep)
        visited.add(node_id)
        stack.append(sub_map[node_id])

    for sid in adj: visit(sid)
    return stack

def _build_filtered_schema(self, assigned_classes: List[Dict[str, Any]]) -> str:
    """
    Build filtered metamodel schema containing ONLY the classes assigned to this subsystem.

    This is a core SOTA Architecture principle: Tactical Planning should NOT see the
    entire metamodel (cognitive overload). It should only see schemas for its assigned classes.

    Args:
        assigned_classes: List of {"class": "Network", "count": "2", "intent": "..."}

    Returns:
        Formatted string describing only the relevant class schemas
    """
    if not assigned_classes:
        return "No specific classes assigned to this subsystem."

    # Extract unique class names
    class_names = set()
    for ac in assigned_classes:
        class_name = ""
        if isinstance(ac, str):
            class_name = ac
        elif isinstance(ac, dict):
            class_name = ac.get("class") or ac.get("class_name") or ac.get("model_name")
        elif hasattr(ac, "class_name"):
            class_name = ac.class_name
        elif hasattr(ac, "model_name"):
            class_name = ac.model_name

        if class_name:
            class_names.add(class_name)

    if not class_names:
        return "No valid classes found in assigned_classes."

    # Build filtered schema
    schema_lines = []
    schema_lines.append("METAMODEL SCHEMAS (Filtered for this subsystem):")
    schema_lines.append("=" * 70)

    for class_name in sorted(class_names):
        analysis = self.analyzer.get_entity_analysis(class_name)
        if not analysis:
            logger.warning(f"No analysis found for class: {class_name}")
            continue

        # Class header
        schema_lines.append(f"\n📦 {class_name}")
        if analysis.description:
            schema_lines.append(f"   {analysis.description}")

        # Required fields
        required_fields = [f for f in analysis.fields.values() if f.is_required]
        if required_fields:
            schema_lines.append("   REQUIRED FIELDS:")
            for field in required_fields:
                field_desc = self._format_field(field)
                schema_lines.append(f"     • {field_desc}")

        # Optional fields
        optional_fields = [f for f in analysis.fields.values() if not f.is_required]
        if optional_fields:
            schema_lines.append("   OPTIONAL FIELDS:")
            for field in optional_fields:
                field_desc = self._format_field(field)
                schema_lines.append(f"     • {field_desc}")

        # Reference fields (critical for linking)
        ref_fields = [f for f in analysis.fields.values() if f.is_reference]
        if ref_fields:
            schema_lines.append("   REFERENCE FIELDS (for linking to other artifacts):")
            for field in ref_fields:
                target = field.reference_target or "Unknown"

                # Use Python type introspection to determine collection vs scalar
                origin = get_origin(field.field_type)
                is_collection = False

                if origin is not None:
                    # Check if origin is a collection type
                    if origin in (list, set, tuple, frozenset):
                        is_collection = True
                    # Ensure origin is a real class before calling issubclass
                    elif isinstance(origin, type):
                        try:
                            is_collection = issubclass(origin, (Sequence, Iterable)) and not issubclass(origin, (str, bytes))
                        except TypeError:
                            is_collection = False

                # Check cardinality as fallback
                is_many = field.cardinality in ("many", "0..*", "1..*") or is_collection

                # Format with strict JSON terminology
                if is_many:
                    schema_lines.append(
                        f"     • {field.field_name} → Array of {target} temp_ids"
                    )
                else:
                    schema_lines.append(
                        f"     • {field.field_name} → Single {target} temp_id"
                    )

    return "\n".join(schema_lines)

def _format_field(self, field) -> str:
    """
    Format a single field for schema display with STRICT TYPE INTROSPECTION.

    ARCHITECTURAL PRINCIPLE: Explicitly explain MCP tool architecture to prevent LLM
    from hallucinating nested JSON objects for reference fields.
    """
    field_type = getattr(field.field_type, "__name__", str(field.field_type))

    # Handle enum fields
    if field.is_enum and field.enum_values:
        enum_vals = ", ".join(field.enum_values[:5])  # Show first 5
        if len(field.enum_values) > 5:
            enum_vals += ", ..."
        return f"{field.field_name}: {field_type} (enum: {enum_vals})"

    # Handle reference fields with STRICT TYPE INTROSPECTION
    if field.is_reference:
        # Use Python type introspection to determine collection vs scalar
        origin = get_origin(field.field_type)
        is_collection = False

        if origin is not None:
            # Check if origin is a collection type
            if origin in (list, set, tuple, frozenset):
                is_collection = True
            # CRITICAL FIX: Ensure origin is a real class before calling issubclass
            elif isinstance(origin, type):
                try:
                    # Only call issubclass if we have actual classes
                    is_collection = issubclass(origin, (Sequence, Iterable)) and not issubclass(origin, (str, bytes))
                except TypeError:
                    # If issubclass fails for any reason, fall back to False
                    is_collection = False

        # Check cardinality as fallback
        is_many = field.cardinality in ("many", "0..*", "1..*") or is_collection

        if is_many:
            # COLLECTION REFERENCE: Array of flat string IDs
            return (
                f"{field.field_name}: Type: array of strings. "
                f"(Provide a flat array of temp_id strings referencing {field.reference_target}. "
                f"DO NOT use nested JSON objects. A downstream agent will use the 'set_reference' "
                f"MCP tool to physically link these later.)"
            )
        else:
            # SCALAR REFERENCE: Single flat string ID
            return (
                f"{field.field_name}: Type: string. "
                f"(Provide a single flat temp_id string referencing {field.reference_target}. "
                f"DO NOT use a nested JSON object. A downstream agent will use MCP tools to "
                f"physically link this later.)"
            )

    # Standard primitive fields
    # Determine JSON type from Python type
    json_type = "string"  # default
    if field_type in ("int", "integer"):
        json_type = "integer"
    elif field_type in ("bool", "boolean"):
        json_type = "boolean"
    elif field_type in ("float", "Decimal"):
        json_type = "number"
    elif get_origin(field.field_type) in (list, set):
        json_type = "array"
    elif get_origin(field.field_type) == dict:
        json_type = "object"

    return f"{field.field_name}: Type: {json_type}"

def _build_complete_metamodel_summary(self) -> str:
    """
    Build a CONCISE summary of the complete metamodel.

    Used for patch additions and Day 2 operations where we don't have
    pre-assigned classes. Still more focused than dumping raw Pydantic schemas.

    Returns:
        Formatted string with all available classes and their key fields
    """
    all_analyses = self.analyzer.get_all_analyses()

    schema_lines = []
    schema_lines.append("METAMODEL OVERVIEW (All Available Classes):")
    schema_lines.append("=" * 70)

    for class_name in sorted(all_analyses.keys()):
        analysis = all_analyses[class_name]

        # Class header with description
        header = f"\n📦 {class_name}"
        if analysis.description:
            header += f" — {analysis.description}"
        schema_lines.append(header)

        # Show only required fields and reference fields (keep it concise)
        required_fields = [f for f in analysis.fields.values() if f.is_required]
        ref_fields = [f for f in analysis.fields.values() if f.is_reference]

        if required_fields:
            field_names = ", ".join(f.field_name for f in required_fields)
            schema_lines.append(f"   Required: {field_names}")

        if ref_fields:
            ref_desc = ", ".join(
                f"{f.field_name} → {f.reference_target}"
                for f in ref_fields
            )
            schema_lines.append(f"   References: {ref_desc}")

    return "\n".join(schema_lines)

def build_instance_dag(self, all_artifacts: Dict[str, List[ArtifactSpec]]) -> Dict[str, Set[str]]:
    dag = {}
    for specs in all_artifacts.values():
        for spec in specs:
            deps = set()
            for ref_val in spec.references.values():
                if isinstance(ref_val, list):
                    # Filter out real UUIDs (strings that aren't temp_ids)
                    # Actually, keep all for now, the executor will resolve.
                    # BUT for building the internal patch DAG, we only care about intra-patch deps.
                    # Wait, the executor's execute_reactive needs the full deps to build events.
                    # If a dep is a real UUID, the done[dep].wait() will block forever if not in done.
                    # FIX: instance_dag should only contain deps that are IN THE CURRENT PATCH.
                    pass

                # Re-evaluating: PlanExecutor.execute_reactive builds 'done' events for all keys in dag.
                # If we include a real UUID in dag, it will block.
                # So, build_instance_dag must filter out deps that aren't in the additions.
                all_patch_tids = {s.temp_id for sp in all_artifacts.values() for s in sp}

                def filter_deps(val):
                    """
                    Strict Fail-Fast validation for reference values.
                    ARCHITECTURAL PRINCIPLE: NO HEURISTICS. If LLM violates schema, fail immediately.
                    """
                    # FAIL FAST: If val is a dict, the LLM hallucinated nested JSON instead of flat ID
                    if isinstance(val, dict):
                        raise ValueError(
                            f"Schema violation: Expected a flat string ID for reference, but received a dictionary: {val}. "
                            f"The LLM must return flat strings or arrays of strings for reference fields, NOT nested objects."
                        )

                    # Handle collections: recurse through list elements
                    if isinstance(val, list):
                        validated = []
                        for item in val:
                            # Fail fast on nested dicts within lists
                            if isinstance(item, dict):
                                raise ValueError(
                                    f"Schema violation: Expected flat string IDs in array, but received dictionary: {item}. "
                                    f"Reference arrays must contain only temp_id strings."
                                )
                            # Only include hashable primitives that are in the current patch
                            if isinstance(item, (str, int)) and item in all_patch_tids:
                                validated.append(item)
                        return validated

                    # Handle scalar references: only allow hashable primitives
                    if isinstance(val, (str, int)):
                        return [val] if val in all_patch_tids else []

                    # Fail on any other unexpected type
                    raise ValueError(
                        f"Schema violation: Reference field contains unexpected type {type(val).__name__}: {val}. "
                        f"Only strings, integers, or lists of strings/integers are allowed."
                    )

                deps.update(filter_deps(ref_val))
            dag[spec.temp_id] = deps
    return dag

def _get_ref_classification(self) -> Dict[str, Any]:
    """Return cached reference classification (computed once per planner instance)."""
    if self._ref_classification is None:
        self._ref_classification = self.analyzer.classify_reference_directions()
    return self._ref_classification

async def _assign_missing_references(
    self,
    subsystem_id: str,
    subsystem_artifacts: List[ArtifactSpec],
    available_context: List[Dict[str, Any]],  # [{temp_id, model_name, intent/task_description}]
) -> None:
    """
    Focused LLM call that fills in reference fields the tactical planner left
    undeclared, using semantic understanding of each artifact's purpose to
    disambiguate between multiple candidates of the same type.

    Only fires when there is at least one undeclared PRIMARY reference field
    whose target type has at least one candidate in scope.
    Leaves fields null when the LLM reports genuine ambiguity.
    """
    ref_classification = self._get_ref_classification()

    # Build lookup: model_name → [ArtifactSpec] from available context
    context_by_type: Dict[str, List[Dict]] = {}
    for ctx in available_context:
        mt = ctx.get("model_name") or ctx.get("entity_type", "")
        if mt:
            context_by_type.setdefault(mt, []).append(ctx)

    # Find all undeclared PRIMARY fields that have at least one candidate
    missing: List[Dict] = []
    for spec in subsystem_artifacts:
        entity_refs = ref_classification.get(spec.model_name, {})
        for field_name, ref_info in entity_refs.items():
            if ref_info.ref_class in ("derived", "circular"):
                continue
            if field_name in spec.references:
                continue
            target_type = ref_info.target_entity_type
            candidates = context_by_type.get(target_type, [])
            if not candidates:
                continue
            missing.append({
                "artifact_temp_id": spec.temp_id,
                "field_name": field_name,
                "required_type": target_type,
                "cardinality": ref_info.cardinality,
                "candidates": [
                    {"temp_id": c["temp_id"], "description": c.get("intent") or c.get("task_description", "")}
                    for c in candidates
                ],
            })

    if not missing:
        return

    # Build the context the LLM sees for disambiguation
    subsystem_ctx = [
        {"temp_id": s.temp_id, "model_name": s.model_name, "task_description": s.task_description}
        for s in subsystem_artifacts
    ]

    from langchain_core.messages import HumanMessage
    prompt = REFERENCE_COMPLETION_PROMPT.format(
        subsystem_id=subsystem_id,
        subsystem_artifacts_json=json.dumps(subsystem_ctx, indent=2),
        available_context_json=json.dumps(available_context, indent=2),
        missing_fields_json=json.dumps(missing, indent=2),
    )
    try:
        data = await self.llm.chat(
            [HumanMessage(content=prompt)],
            response_model=ReferenceCompletionResponse
        )
        if not data:
            logger.warning("[ref_completion] No structured response returned for subsystem %s", subsystem_id)
            return
    except Exception as e:
        logger.warning("[ref_completion] LLM call failed for subsystem %s: %s", subsystem_id, e)
        return

    # Index specs by temp_id for fast lookup
    spec_index = {s.temp_id: s for s in subsystem_artifacts}

    applied = 0
    for assignment in data.assignments:
        temp_id = assignment.artifact_temp_id
        field_name = assignment.field_name
        value = assignment.assignment

        if not temp_id or not field_name or value is None:
            continue
        spec = spec_index.get(temp_id)
        if not spec:
            continue
        # Don't overwrite anything the LLM planner or a prior assignment already set
        if field_name in spec.references:
            continue

        spec.references[field_name] = value
        applied += 1
        logger.info(
            "[ref_completion] %s (%s).%s → %s",
            temp_id, spec.model_name, field_name, value,
        )

    if applied:
        logger.info("[ref_completion] Subsystem %s: applied %d reference assignment(s)", subsystem_id, applied)

def _complete_plan_dependencies(
    self,
    all_specs: Dict[str, List[ArtifactSpec]],
    subsystem_map: Dict[str, str],
) -> None:
    """
    Deterministic post-processing pass that fills in reference fields the LLM
    planner missed, using the MetamodelAnalyzer's reference classification.

    Rules:
    - Only fills PRIMARY reference fields (DERIVED = reconciler; CIRCULAR = two-phase).
    - Never overwrites a reference already declared by the planner.
    - Scoping: prefers same-subsystem candidates; falls back to plan-wide.
    - Only auto-fills when there is EXACTLY ONE candidate in scope (ambiguous = skip).
    """
    ref_classification = self._get_ref_classification()
    filled = 0

    for model_name, specs in all_specs.items():
        entity_analysis = self.analyzer.get_entity_analysis(model_name)
        if not entity_analysis:
            continue

        entity_refs = ref_classification.get(model_name, {})

        for spec in specs:
            spec_subsystem = subsystem_map.get(spec.temp_id)

            for field_name, ref_info in entity_refs.items():
                # DERIVED refs are maintained by the reconciler (back-reference lists).
                # CIRCULAR refs require two-phase commit — worker intentionally skips them.
                if ref_info.ref_class in ("derived", "circular"):
                    continue

                # Respect whatever the LLM planner already declared.
                if field_name in spec.references:
                    continue

                target_type = ref_info.target_entity_type
                candidates = all_specs.get(target_type, [])
                if not candidates:
                    continue

                # Prefer same-subsystem candidates to respect subsystem isolation.
                same_sub = [
                    c for c in candidates
                    if subsystem_map.get(c.temp_id) == spec_subsystem
                ]
                pool = same_sub if same_sub else candidates

                # Never create self-references.
                pool = [c for c in pool if c.temp_id != spec.temp_id]
                if not pool:
                    continue

                # Ambiguous: multiple candidates — leave for worker to resolve at runtime.
                if len(pool) > 1:
                    logger.debug(
                        "[dep_completion] Ambiguous %s.%s → %s: %d candidates, skipping",
                        model_name, field_name, target_type, len(pool),
                    )
                    continue

                candidate = pool[0]
                fa = entity_analysis.fields.get(field_name)
                if fa and fa.cardinality == "many":
                    spec.references[field_name] = [candidate.temp_id]
                else:
                    spec.references[field_name] = candidate.temp_id

                filled += 1
                logger.info(
                    "[dep_completion] %s (%s).%s → %s (%s)",
                    spec.temp_id, model_name, field_name,
                    candidate.temp_id, target_type,
                )

    if filled:
        logger.info("[dep_completion] Completed %d missing reference(s) across plan", filled)

def validate_dag(self, dag: Dict[str, Set[str]]) -> List[str]:
    errors = []
    all_ids = set(dag.keys())
    for tid, deps in dag.items():
        for dep in deps:
            if dep not in all_ids: errors.append(f"Unknown ref: {tid}->{dep}")
    # Simple cycle check
    visited = set()
    path = set()
    def has_cycle(v):
        visited.add(v)
        path.add(v)
        for neighbor in dag.get(v, []):
            if neighbor not in visited:
                if has_cycle(neighbor): return True
            elif neighbor in path: return True
        path.remove(v)
        return False
    for node in dag:
        if node not in visited:
            if has_cycle(node): errors.append("Cycle detected in instance DAG")
    return errors

def _organize_into_phases(self, all_artifacts: Dict[str, List[ArtifactSpec]]) -> List[PhaseExecution]:
    """Convert grouped artifacts into sequential phases based on Metamodel layers."""
    metamodel_phases = self.graph.get_creation_phases()
    results = []
    for mp in metamodel_phases:
        phase_artifacts = []
        for model_name in mp.entities:
            if model_name in all_artifacts:
                phase_artifacts.extend(all_artifacts[model_name])
        if phase_artifacts:
            results.append(PhaseExecution(
                phase_index=mp.phase_index,
                artifacts=phase_artifacts,
                dependencies_required=mp.dependencies_satisfied
            ))
    return results

async def _generate_phase_goals(
    self, user_goal: str, phases: List[PhaseExecution]
) -> Dict[int, Dict[str, str]]:
    """Generate LLM summaries for each phase in the execution flow."""
    if not phases:
        return {}

    phase_context = [
        {
            "phase_index": phase.phase_index,
            "artifact_count": len(phase.artifacts),
            "entities": sorted({a.model_name for a in phase.artifacts}),
            "example_tasks": [a.task_description for a in phase.artifacts[:3]],
        }
        for phase in phases
    ]

    try:
        from langchain_core.messages import HumanMessage

        parsed = await self.llm.chat(
            [HumanMessage(content=PHASE_GOALS_PROMPT.format(
                user_goal=user_goal,
                phase_context=json.dumps(phase_context, indent=2),
            ))],
            response_model=PhaseGoalsResponse
        )
        if not parsed:
            return {}

        summaries: Dict[int, Dict[str, str]] = {}
        for item in parsed.phases:
            summaries[item.phase_index] = {
                "phase_name": item.phase_name,
                "phase_goal": item.phase_goal,
            }
        return summaries
    except Exception as exc:
        logger.warning(f"Failed to generate phase goals: {exc}")
        return {}

def _build_entity_descriptions(self) -> List[str]:
    return [f"- {name}: {a.description}" for name, a in self.analyzer.get_all_analyses().items()]

async def _emit_event(self, event_type: str, data: Dict[str, Any]):
    """Emit an event via the event_callback if configured."""
    if self.event_callback:
        try:
            await self.event_callback(event_type, data)
        except Exception as e:
            logger.warning(f"Event emission failed for {event_type}: {e}")
